    'vc.route.4.t': 'Growth and analytics',
    'vc.route.4.d': 'Experience with metrics, users and how startups scale.',
    'vc.route.5.t': 'Angel investing',
    'vc.route.5.d': 'Investing your own small amounts to build judgement and a track record.',
