    'esg.resx.2.t': 'Overview of the EU Taxonomy Regulation',
    'esg.resx.2.d': 'How economic activities are classified as sustainable.',
    'esg.resx.3.t': 'Application guide for the legal profession',
    'esg.resx.3.d': 'How to write a strong motivation letter for a trainee position.',
    'esg.resx.4.t': 'List of firms with an ESG practice',
    'esg.resx.4.d': 'A verified overview of firms offering this practice area, once available.',
    'esg.resx.5.t': 'Basics of corporate governance',
