    'cfa.vac.title': 'Financial & deal advisory vacancies',
    'cfa.vac.text': 'We only show real, current openings with a link to the employer. Internships, traineeships and adviser roles appear here. In the meantime, browse all current vacancies.',
    'cfa.vac.all': 'View all vacancies',
