    'cpo.law.4.t': 'Culture and collaboration',
    'cpo.law.4.d': 'Working on culture, behaviour and collaboration.',
    'cpo.law.5.t': 'HR transformation',
    'cpo.law.5.d': 'Renewing the HR function, processes and systems.',
    'cpo.div.label': 'Sub-areas',
    'cpo.div.title': 'The main sub-areas',
    'cpo.div.text': 'People & organisation is broad, and many consultants specialise over time in a theme or a sector.',
    'cpo.div.0.t': 'Organisation design',
