    'cpo.div.1.t': 'Change management',
    'cpo.div.1.d': 'Guiding change and transformation.',
    'cpo.div.2.t': 'Talent and leadership',
    'cpo.div.2.d': 'Talent development, succession and leadership.',
    'cpo.div.3.t': 'Reward and performance',
