    /* Private equity page */
    'pe.badge': 'Finance-carrièrepad',
    'pe.h1': 'Private Equity',
    'pe.sub': 'Ontdek wat private equity is, hoe fondsen in bedrijven investeren, wat het werk inhoudt en hoe studenten zich kunnen voorbereiden op stages en analistenfuncties.',
    'pe.cta.vac': 'Bekijk vacatures',
    'pe.cta.paths': 'Ontdek finance-paden',
    'pe.intro.label': 'Introductie',
    'pe.intro.title': 'Wat is private equity?',
    'pe.intro.p': 'Private equity betekent dat er geld rechtstreeks in bedrijven wordt geïnvesteerd die niet aan een beurs genoteerd zijn. Investeerders kopen een belang in een onderneming, werken er een aantal jaren aan om die waardevoller te maken en verkopen dat belang daarna, idealiter met winst. Het geld komt uit een private equity-fonds, dat kapitaal bundelt van grote investeerders zoals pensioenfondsen, verzekeraars en vermogende particulieren.',
    'pe.what.h': 'Hoe het kort gezegd werkt',
    'pe.what1.t': 'Wat het is',
    'pe.what1.d': 'Investeren in niet-beursgenoteerde bedrijven, of een beursgenoteerd bedrijf kopen en van de beurs halen, met als doel de waarde te laten groeien en later te verkopen.',
    'pe.what2.t': 'Hoe fondsen geld verdienen',
    'pe.what2.d': 'Door de prestaties van een bedrijf te verbeteren en tegen de juiste prijs te kopen en verkopen. Firmas gebruiken vaak schuld om een aankoop te financieren, wat het rendement op hun eigen kapitaal kan verhogen.',
    'pe.what3.t': 'Waarom bedrijven verkopen',
    'pe.what3.d': 'Een oprichter gaat met pensioen, een familie verzilvert, een concern verkoopt een onderdeel, of een bedrijf heeft kapitaal en kennis nodig om te groeien. Private equity biedt geld en praktische steun in ruil voor eigendom.',
    'pe.what4.t': 'Waarom studenten het aantrekkelijk vinden',
    'pe.what4.d': 'Het combineert finance, strategie en echte zeggenschap over zakelijke beslissingen. Het werk is analytisch en afwisselend, je krijgt vroeg verantwoordelijkheid en de beloning behoort tot de hoogste in finance.',
    'pe.do.label': 'Wat ze doen',
    'pe.do.title': 'Wat private equity-firmas doen',
    'pe.deal.label': 'Stap voor stap',
    'pe.deal.title': 'Hoe een private equity-deal werkt',
    'pe.types.label': 'Soorten',
    'pe.types.title': 'Soorten private equity-firmas',
    'pe.roles.label': 'Functies',
    'pe.roles.title': 'Functies in private equity',
    'pe.role.tasks': 'Belangrijkste taken',
    'pe.role.skills': 'Kernvaardigheden',
    'pe.role.level': 'Doorgaans niveau',
    'pe.ia.label': 'Juniors',
    'pe.ia.title': 'Wat stagiairs en analisten doen',
    'pe.ia.text': 'Junior teamleden doen veel van het voorwerk waarop een deal wordt gebouwd.',
    'pe.skills.label': 'Vaardigheden',
    'pe.skills.title': 'Vaardigheden die je nodig hebt',
    'pe.routes.label': 'Routes',
    'pe.routes.title': 'Beste routes naar private equity',
    'pe.vs.label': 'Vergelijk',
    'pe.vs.title': 'Private equity versus andere finance-paden',
    'pe.emp.label': 'Werkgevers',
    'pe.emp.title': 'Private equity-werkgevers in Nederland',
    'pe.emp.text': 'Een selectie van bekende private equity-partijen die actief zijn in Nederland, ingedeeld naar type. We noemen alleen partijen die we hebben geverifieerd en breiden dit na verloop van tijd uit.',
    'pe.emp.pending': 'Deze voegen we toe zodra ze zijn geverifieerd.',
    'pe.vac.label': 'Vacatures',
    'pe.vac.title': 'Private equity-vacatures',
    'pe.vac.text': 'We tonen alleen echte, actuele vacatures met een link naar de werkgever. Stages, werkstudentrollen, analistenfuncties en off-cycle stages verschijnen hier. Bekijk in de tussentijd alle actuele vacatures.',
    'pe.vac.all': 'Bekijk alle vacatures',
    'pe.prep.label': 'Voorbereiding',
    'pe.prep.title': 'Hoe je je voorbereidt als student',
    'pe.res.label': 'Hulpmiddelen',
    'pe.res.title': 'Aanbevolen hulpmiddelen',
