    'vc.vac.label': 'Vacatures',
    'vc.vac.title': 'Venture capital-vacatures',
    'vc.vac.text': 'We tonen alleen echte, actuele vacatures met een link naar de werkgever. Stages, werkstudentrollen en analistenfuncties verschijnen hier. Bekijk in de tussentijd alle actuele vacatures.',
    'vc.vac.all': 'Bekijk alle vacatures',
