    'elp.skill.9': 'Strategisch inzicht',
    'elp.routes.label': 'Instromen',
    'elp.routes.title': 'Hoe je in employment, labour & pensions komt',
    'elp.routes.text': 'De meeste routes lopen via de master rechten met een specialisatie in arbeidsrecht of privaatrecht, gevolgd door een stage of traineeship bij een kantoor. Affiniteit met mensen en organisaties is een pluspunt.',
    'elp.route.0.t': 'Master arbeidsrecht of privaatrecht',
    'elp.route.0.d': 'De meest directe route, met vakken die rechtstreeks aansluiten op de praktijk.',
    'elp.route.1.t': 'Stage tijdens de master',
