    'elp.resx.2.t': 'Overzicht van medezeggenschap',
    'elp.resx.2.d': 'De rol en rechten van de ondernemingsraad, kort samengevat.',
    'elp.resx.3.t': 'Sollicitatiegids voor de advocatuur',
    'elp.resx.3.d': 'Hoe je een sterke motivatie schrijft voor een stagiairsplek.',
    'elp.resx.4.t': 'Lijst van kantoren met employment-praktijk',
