    'esg.skill.9': 'Strategisch inzicht',
    'esg.routes.label': 'Instromen',
    'esg.routes.title': 'Hoe je in ESG komt',
    'esg.routes.text': 'De meeste routes lopen via de master rechten met een specialisatie in ondernemingsrecht of milieurecht, gevolgd door een stage of traineeship bij een kantoor. Affiniteit met duurzaamheid en regelgeving is een pluspunt.',
    'esg.route.0.t': 'Master ondernemingsrecht of milieurecht',
    'esg.route.0.d': 'De meest directe route, met vakken die rechtstreeks aansluiten op de praktijk.',
    'esg.route.1.t': 'Stage tijdens de master',
    'esg.route.1.d': 'Praktijkervaring opdoen bij een kantoor voor het afstuderen.',
    'esg.route.2.t': 'Traineeship na afstuderen',
    'esg.route.2.d': 'Gestructureerde programma\'s waarin je meerdere praktijkgroepen doorloopt.',
    'esg.route.3.t': 'Vakken volgen over duurzaamheidsrecht',
    'esg.route.3.d': 'Verdiepende keuzevakken laten affiniteit met het bredere vakgebied zien.',
    'esg.route.4.t': 'Studieverenigingen en commissies',
    'esg.route.4.d': 'Een bestuurs- of commissiejaar bij een studievereniging bouwt netwerk en ervaring op.',
    'esg.route.5.t': 'Publiceren in vaktijdschriften',
    'esg.route.5.d': 'Een noot of artikel over duurzaamheidsrecht valt op bij sollicitaties.',
    'esg.route.6.t': 'Werkervaring bij een duurzaamheidsafdeling',
    'esg.route.6.d': 'Een stage bij de duurzaamheidsafdeling van een onderneming geeft inzicht vanuit de cliëntkant.',
    'esg.route.7.t': 'Netwerken met advocaten en alumni',
    'esg.route.7.d': 'Koffiegesprekken en alumnicontacten openen veel deuren bij het solliciteren.',
    'esg.prep.label': 'Voorbereiding',
    'esg.prep.title': 'Hoe je je voorbereidt als student',
    'esg.prep.text': 'Voorbereiding werkt het best als ze ruim voor de sollicitatie begint. Kantoren toetsen niet alleen juridische kennis, maar ook of iemand snel veranderende regelgeving kan volgen en begrijpelijk kan uitleggen.',
    'esg.prep.0.t': 'Volg vakken duurzaamheidsrecht en ondernemingsrecht',
    'esg.prep.0.d': 'Bouw een stevige basis in regelgeving rond duurzaamheid en corporate governance.',
    'esg.prep.1.t': 'Lees over CSRD en CSDDD',
    'esg.prep.1.d': 'Volg hoe deze Europese richtlijnen worden geïmplementeerd en toegepast.',
    'esg.prep.2.t': 'Doe een relevante stage',
    'esg.prep.2.d': 'Elke stage bij een kantoor of duurzaamheidsafdeling versterkt je sollicitatie.',
    'esg.prep.3.t': 'Oefen sollicitatiegesprekken',
    'esg.prep.3.d': 'Bereid je voor op vragen over motivatie, casuïstiek en actualiteiten.',
    'esg.prep.4.t': 'Maak een cv van een pagina',
    'esg.prep.4.d': 'Houd het helder en gericht op relevante ervaring en resultaten.',
    'esg.prep.5.t': 'Netwerk vroeg',
    'esg.prep.5.d': 'Benader advocaten en alumni voordat de sollicitatierondes opengaan.',
    'esg.prep.6.t': 'Volg actualiteiten in de duurzaamheidsregelgeving',
    'esg.prep.6.d': 'Nieuwe Europese richtlijnen volgen elkaar snel op in dit vakgebied.',
    'esg.prep.7.t': 'Verbeter je Engels',
    'esg.prep.7.d': 'Europese regelgeving en internationale cliënten vereisen vaak Engelstalig werk.',
    'esg.vs.label': 'Vergelijk',
    'esg.vs.title': 'ESG versus andere praktijkgebieden',
    'esg.vs.text': 'Deze praktijkgebieden overlappen vaak in dezelfde dossiers, waardoor studenten ze soms door elkaar halen. Het onderscheid zit vooral in welk deel van de onderneming of het geschil centraal staat.',
    'esg.vs.0.t': 'ESG vs Corporate/M&A',
    'esg.vs.0.d': 'Corporate/M&A begeleidt de transactie zelf. ESG beoordeelt de duurzaamheids- en governancerisico\'s die bij die transactie horen.',
    'esg.vs.1.t': 'ESG vs Commercial',
    'esg.vs.1.d': 'Commercial stelt het contract op. ESG toetst of de duurzaamheidsclaims en -clausules daarin houdbaar zijn.',
    'esg.vs.2.t': 'ESG vs Administrative Law',
    'esg.vs.2.d': 'Administrative Law behandelt geschillen met de overheid, bijvoorbeeld over milieuvergunningen. ESG adviseert breder over duurzaamheidsregelgeving richting de eigen onderneming.',
    'esg.vs.3.t': 'ESG vs Employment, Labour & Pensions',
    'esg.vs.3.d': 'Employment gaat over de arbeidsrelatie zelf. ESG behandelt de bredere sociale verantwoordelijkheid van een onderneming in haar keten.',
    'esg.vs.4.t': 'ESG vs Dispute Resolution',
    'esg.vs.4.d': 'Dispute Resolution voert de procedure als een klimaat- of duurzaamheidsgeschil escaleert. ESG richt zich op het voorkomen daarvan door compliance.',
    'esg.emp.label': 'Werkgevers',
    'esg.emp.title': 'Kantoren met een ESG-praktijk in Nederland',
    'esg.emp.text': 'We noemen hier alleen kantoren waarvan een specifieke ESG-praktijk is geverifieerd. Op dit moment hebben we voor dit praktijkgebied nog geen kantoor kunnen bevestigen.',
    'esg.emp.soon': 'We werken aan het verifiëren van kantoren met een specifieke ESG-praktijk in Nederland. Bekijk in de tussentijd alle werkgevers of alle openstaande vacatures.',
    'esg.emp.allcompanies': 'Bekijk alle werkgevers',
    'esg.vac.label': 'Vacatures',
    'esg.vac.title': 'ESG-vacatures',
    'esg.vac.text': 'We tonen hier alleen vacatures van kantoren met een geverifieerde ESG-praktijk. Zodra we die verificatie hebben afgerond, verschijnen relevante vacatures op deze plek. Bekijk in de tussentijd alle actuele vacatures.',
    'esg.vac.all': 'Bekijk alle vacatures',
