    'pp.role.1.d': 'De verplichte traineeship van drie jaar direct na het afstuderen.',
    'pp.role.1.tasks': 'Aanbestedingsdocumenten mee opstellen, concept-adviezen schrijven, cliëntcontact onder begeleiding.',
    'pp.role.1.skills': 'Nauwkeurig schrijven, oog voor detail, brede juridische basis.',
    'pp.role.1.level': 'Startend, direct na de master.',
    'pp.role.2.n': 'Advocaat / Associate',
    'pp.role.2.d': 'Behandelt dossiers zelfstandig na de beëdiging als advocaat.',
    'pp.role.2.tasks': 'Kort gedingen voeren, aanbestedingsdocumenten opstellen, cliënten adviseren over aanbestedingsstrategie.',
    'pp.role.2.skills': 'Analytisch vermogen, overtuigingskracht, dossierregie.',
    'pp.role.2.level': 'Na de stagejaren, beëdigd advocaat.',
