    're.routes.label': 'Instromen',
    're.routes.title': 'Hoe je in real estate komt',
    're.routes.text': 'De meeste routes lopen via de master rechten met een specialisatie in privaatrecht of ondernemingsrecht, gevolgd door een stage of traineeship bij een kantoor. Affiniteit met vastgoed en gebiedsontwikkeling is een pluspunt.',
    're.route.0.t': 'Master privaatrecht of ondernemingsrecht',
    're.route.0.d': 'De meest directe route, met vakken die rechtstreeks aansluiten op de praktijk.',
    're.route.1.t': 'Stage tijdens de master',
