    're.route.2.t': 'Traineeship na afstuderen',
    're.route.2.d': 'Gestructureerde programma\'s waarin je meerdere praktijkgroepen doorloopt.',
    're.route.3.t': 'Vakken volgen over goederenrecht en huurrecht',
