    'cfa.vs.label': 'Vergelijk',
    'cfa.vs.title': 'Financial & Deal Advisory versus andere paden',
    'cfa.vs.text': 'Deze paden overlappen soms, waardoor studenten ze door elkaar halen. Het onderscheid zit vooral in de rol en het deel van de deal.',
    'cfa.vs.0.t': 'Financial & Deal Advisory vs Strategy Consulting',
    'cfa.vs.0.d': 'Strategy beoordeelt de commerciele aantrekkelijkheid van een deal. Deal advisory beoordeelt de financiele cijfers en risico\'s eronder.',
    'cfa.vs.1.t': 'Financial & Deal Advisory vs Investment Banking',
    'cfa.vs.1.d': 'Investment banking begeleidt de transactie en de financiering. Deal advisory levert de financiele analyse en due diligence eromheen.',
    'cfa.vs.2.t': 'Financial & Deal Advisory vs Transaction Services (finance)',
    'cfa.vs.2.d': 'Transaction services is het finance-pad dat de financiele due diligence beschrijft. Dit consulting-pad kijkt breder naar de advies- en dealkant.',
    'cfa.vs.3.t': 'Financial & Deal Advisory vs Restructuring & Insolvency (legal)',
    'cfa.vs.3.d': 'De juridische kant van herstructurering hoort bij het legal-pad. Deal advisory doet de financiele kant van de turnaround.',
    'cfa.vs.4.t': 'Financial & Deal Advisory vs Operations Consulting',
    'cfa.vs.4.d': 'Operations verbetert de uitvoering van een onderneming. Deal advisory beoordeelt en verbetert de financiele positie, vaak rond een transactie.',
    'cfa.emp.label': 'Werkgevers',
    'cfa.emp.title': 'Deal-advisorybureaus in Nederland',
    'cfa.emp.text': 'Een selectie van bedrijven met een deal-advisory- of turnaroundpraktijk en een vestiging in Nederland. We noemen alleen bedrijven waarvan de praktijk bevestigd is.',
    'cfa.emp.text2': 'De bredere corporate-finance- en M&A-wereld, waaronder investment banks en boutiques, vind je op deze site onder finance.',
    'cfa.empcat.0': 'Deal advisory bij de Big Four',
    'cfa.empcat.1': 'Onafhankelijke advies- en turnaroundbureaus',
