    'cop.law.5.t': 'Lean en operational excellence',
    'cop.law.5.d': 'Een cultuur van continu verbeteren opbouwen.',
    'cop.div.label': 'Deelgebieden',
    'cop.div.title': 'De belangrijkste deelgebieden',
    'cop.div.text': 'Operations is breed, en veel consultants specialiseren zich na verloop van tijd in een sector of een type vraagstuk.',
    'cop.div.0.t': 'Supply chain en logistiek',
    'cop.div.0.d': 'De keten van inkoop tot levering.',
    'cop.div.1.t': 'Productie en manufacturing',
    'cop.div.1.d': 'Het efficienter maken van productieprocessen.',
    'cop.div.2.t': 'Inkoop en procurement',
    'cop.div.2.d': 'Inkoopstrategie en het beheer van leveranciers.',
    'cop.div.3.t': 'Lean en operational excellence',
    'cop.div.3.d': 'Continu verbeteren en verspilling verminderen.',
    'cop.div.4.t': 'Service operations',
    'cop.div.4.d': 'Het verbeteren van dienstverlenende processen.',
    'cop.dp.label': 'Stap voor stap',
    'cop.dp.title': 'Hoe een operationsproject verloopt',
    'cop.dp.text': 'De meeste operationsprojecten doorlopen een vergelijkbaar traject, van het meten van de huidige situatie tot het borgen van de verbetering. Veel bureaus gebruiken hierbij een gestructureerde aanpak zoals Lean.',
    'cop.dp.text2': 'Wie welke stap doet, hangt af van senioriteit. Jonge consultants doen veel van het meten en analyseren op de werkvloer, terwijl senior consultants de aanpak bepalen en de verandering met de client leiden.',
    'cop.dp.text3': 'De waarde van een operationsproject zit vaak in de laatste stap: een verbetering die niet wordt geborgd, verdwijnt na verloop van tijd weer.',
    'cop.dp.0': 'Diagnose',
    'cop.dp.1': 'Meten',
    'cop.dp.2': 'Analyseren',
    'cop.dp.3': 'Verbeteren',
    'cop.dp.4': 'Implementeren',
    'cop.dp.5': 'Borgen',
    'cop.dp.caption': 'Een vereenvoudigd overzicht van een operationsproject: de diagnose, het meten van de huidige situatie, het analyseren van knelpunten, het verbeteren, het implementeren, en het borgen van het resultaat.',
    'cop.roles.label': 'Functies',
    'cop.roles.title': 'Functies in de operations-praktijk',
    'cop.roles.text': 'Elke stap in de hierarchie verschuift de nadruk verder van analyse op de werkvloer naar het leiden van teams en het onderhouden van de clientrelatie. De meeste consultants doorlopen deze ladder bij hetzelfde bedrijf, al is een overstap naar een operationsrol in de business op elk niveau gebruikelijk.',
    'cop.role.tasks': 'Belangrijkste taken',
    'cop.role.skills': 'Kernvaardigheden',
    'cop.role.level': 'Doorgaans niveau',
    'cop.role.0.n': 'Analyst / Consultant',
    'cop.role.0.d': 'De startfunctie direct na een bachelor of master.',
    'cop.role.0.tasks': 'Processen meten, data analyseren, verbeteringen mee ontwerpen.',
    'cop.role.0.skills': 'Analytisch vermogen, nauwkeurigheid, praktische instelling.',
    'cop.role.0.level': 'Startend, na de studie.',
