    'cop.prep.label': 'Voorbereiding',
    'cop.prep.title': 'Hoe je je voorbereidt als student',
    'cop.prep.text': 'Voorbereiding werkt het best als ze ruim voor de sollicitatie begint. Bedrijven toetsen je analyse en of je een verbetering praktisch en overtuigend kunt uitleggen.',
    'cop.prep.0.t': 'Oefen cases',
