    'csu.role.0.tasks': 'Uitstoot en data analyseren, roadmaps mee opstellen, rapportages voorbereiden.',
    'csu.role.0.skills': 'Analytisch vermogen, nauwkeurigheid, kennis van duurzaamheid.',
