    'csu.role.4.n': 'Partner / Director',
    'csu.role.4.d': 'Draagt eindverantwoordelijkheid voor clienten en de praktijk.',
    'csu.role.4.tasks': 'Clientrelaties, acquisitie, eindverantwoordelijkheid voor het bedrijf.',
