    'csu.prep.label': 'Voorbereiding',
    'csu.prep.title': 'Hoe je je voorbereidt als student',
    'csu.prep.text': 'Voorbereiding werkt het best als ze ruim voor de sollicitatie begint. Bedrijven toetsen je analyse en of je duurzaamheid concreet en geloofwaardig kunt maken.',
    'csu.prep.0.t': 'Verdiep je in duurzaamheid',
